{"version":3,"names":["meetOrSliceTypes","meet","slice","none","alignEnum","reduce","prev","name","spacesRegExp","extractViewBox","props","viewBox","preserveAspectRatio","params","Array","isArray","trim","split","map","Number","length","some","isNaN","console","warn","modes","align","meetOrSlice","minX","minY","vbWidth","vbHeight"],"sources":["extractViewBox.ts"],"sourcesContent":["import { NumberProp } from './types';\n\nexport const meetOrSliceTypes: {\n  [meetOrSlice: string]: number;\n} = {\n  meet: 0,\n  slice: 1,\n  none: 2,\n};\n\nexport const alignEnum: { [align: string]: string } = [\n  'xMinYMin',\n  'xMidYMin',\n  'xMaxYMin',\n  'xMinYMid',\n  'xMidYMid',\n  'xMaxYMid',\n  'xMinYMax',\n  'xMidYMax',\n  'xMaxYMax',\n  'none',\n].reduce((prev: { [align: string]: string }, name) => {\n  prev[name] = name;\n  return prev;\n}, {});\n\nconst spacesRegExp = /\\s+/;\n\nexport default function extractViewBox(props: {\n  viewBox?: string | NumberProp[];\n  preserveAspectRatio?: string;\n}) {\n  const { viewBox, preserveAspectRatio } = props;\n\n  if (!viewBox) {\n    return null;\n  }\n\n  const params = (\n    Array.isArray(viewBox) ? viewBox : viewBox.trim().split(spacesRegExp)\n  ).map(Number);\n\n  if (params.length !== 4 || params.some(isNaN)) {\n    console.warn('Invalid `viewBox` prop:' + viewBox);\n    return null;\n  }\n\n  const modes = preserveAspectRatio\n    ? preserveAspectRatio.trim().split(spacesRegExp)\n    : [];\n  const align = modes[0];\n  const meetOrSlice = modes[1];\n\n  return {\n    minX: params[0],\n    minY: params[1],\n    vbWidth: params[2],\n    vbHeight: params[3],\n    align: alignEnum[align] || 'xMidYMid',\n    meetOrSlice: meetOrSliceTypes[meetOrSlice] || 0,\n  };\n}\n"],"mappings":"iJAEO,GAAMA,iBAEZ,CAAG,CACFC,IAAI,CAAE,CADJ,CAEFC,KAAK,CAAE,CAFL,CAGFC,IAAI,CAAE,CAHJ,CAFG,C,0CAQA,GAAMC,UAAsC,CAAG,CACpD,UADoD,CAEpD,UAFoD,CAGpD,UAHoD,CAIpD,UAJoD,CAKpD,UALoD,CAMpD,UANoD,CAOpD,UAPoD,CAQpD,UARoD,CASpD,UAToD,CAUpD,MAVoD,EAWpDC,MAXoD,CAW7